import{_ as r,o as t,c as a,a3 as n}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse(`{"title":"14. Minimum Wages","description":"","frontmatter":{"title":"14. Minimum Wages","eba":"Children's Services Award 2010","topics":["hours","overtime","wages","classifications","employment","disputes","preliminary"]},"headers":[],"relativePath":"ebas/childrens-services/wages/14-minimum-wages.md","filePath":"ebas/childrens-services/wages/14-minimum-wages.md"}`),i={name:"ebas/childrens-services/wages/14-minimum-wages.md"};function s(o,e,l,p,c,h){return t(),a("div",null,[...e[0]||(e[0]=[n(`<h1 id="_14-minimum-wages" tabindex="-1">14. Minimum Wages <a class="header-anchor" href="#_14-minimum-wages" aria-label="Permalink to &quot;14. Minimum Wages&quot;">​</a></h1><p><strong>NOTE: A transitional pay equity order taken to have been made pursuant to item 30A of Schedule 3A to the</strong> <em>Fair Work (Transitional Provisions and Consequential Amendments) Act 2009</em> (Cth) has effect in accordance with that item. A relevant transitional pay equity order operates in Queensland as provided for in items 30A(6) and (7).</p><ol><li>The total minimum weekly rate of wages payable to persons employed pursuant to this award will be as set out in the following table.</li></ol><p><strong>Classification</strong> <strong>Minimum weekly rate</strong> <strong>Minimum hourly rate</strong></p><hr><pre><code>                                                              \\$                        \\$
</code></pre><p><strong>Support Worker</strong> Level 1.1 On commencement 948.00 24.95 Level 2.1 On commencement 977.00 25.71 Level 2.2 After 1 year* 1009.10 26.56 Level 3.1 On commencement 1068.40 28.12 <strong>Children&#39;s Services Employee</strong> Level 1.1 On commencement 948.00 24.95 Level 2.1 On commencement 977.00 25.71 Level 2.2 After 1 year* 1009.10 26.56 Level 3A.1** On commencement 1052.00 27.68 Level 3A.2** After 1 year* 1068.40 28.12 Level 3.1 On commencement 1068.40 28.12 Level 3.2 After 1 year* 1105.30 29.09 Level 3.3 After 2 years* 1140.10 30.00 Level 3.4 (Diploma) 1203.10 31.66 Level 4A.1 On commencement 1140.10 30.00 Level 4A.2 After 1 year* 1156.00 30.42 Level 4A.3 After 2 years* 1171.70 30.83 Level 4A.4 After 3 years* 1188.20 31.27 Level 4A.5 After 4 years* 1204.00 31.68 Level 4.1 On commencement 1258.60 33.12 Level 4.2 After 1 year* 1277.80 33.63 Level 4.3 After 2 years* 1296.90 34.13 Level 5A.1 On commencement 1316.10 34.63 Level 5A.2 After 1 year* 1335.20 35.14 Level 5A.3 After 2 years* 1354.10 35.63 Level 5.1 On commencement 1316.10 34.63 Level 5.2 After 1 year* 1335.20 35.14 Level 5.3 After 2 years* 1354.10 35.63 Level 5.4*** 1359.00 35.76 Level 6A.1 On commencement 1517.60 39.94 Level 6A.2 After 1 year* 1536.60 40.44 Level 6A.3 After 2 years* 1555.40 40.93 <strong>Children&#39;s Services Employee---Director</strong> Level 6.1 On commencement 1517.60 39.94 Level 6.2 After 1 year* 1536.60 40.44 Level 6.3 After 2 years* 1555.40 40.93 Level 6.4 On commencement 1613.50 42.46 Level 6.5 After 1 year* 1628.30 42.85 Level 6.6 After 2 years* 1647.70 43.36 Level 6.7 On commencement 1667.40 43.88 Level 6.8 After 1 year * 1686.40 44.38 Level 6.9 After 2 years* 1705.50 44.88</p><p>*Reference to a year or years of service is to service in the industry</p><p>**Former Western Australian &#39;E&#39; worker classification</p><p>***An Assistant Director who holds an Advanced Diploma (AQF 6/3 year qualified) must be paid no less than Level 5.4</p><ol><li><p>Progression for children&#39;s services employees</p><p>a. Progression from one level to the next within a classification is subject to an employee meeting the following criteria:</p><pre><code>i.  competency at the existing level;

ii. 12 months experience at that level (or in the case of
    employees employed for 19 hours or less per week, 24 months)
    and in-service training as required; and

iii. demonstrated ability to acquire the skills necessary for
     advancement to the next pay point.
</code></pre><p>b. Where an employee is deemed not to have met the requisite competency at their existing level at the time of the appraisal, progression may be deferred for a period of three months provided that:</p><pre><code>i.  the employee is notified in writing of the reasons for the
    deferral;

ii. the employee has, in the previous 12 months, been provided
    with the in‑service training required to attain a higher pay
    point; and

iii. following any deferral, the employee is provided with the
     training necessary to advance to the next level.
</code></pre><p>c. Where an appraisal has been deferred for operational reasons beyond the control of either party and the appraisal subsequently deems the employee to have met the requirements of clause 14.2(a), any increase in wages will be back paid to the 12 (or 24) month anniversary date of the previous progression.</p><p>d. An employee whose progression has been refused or deferred may invoke the provisions of <a href="/eba/ebas/childrens-services/consultation-disputes/9-dispute-resolution.html">clause 9</a>---Dispute resolution. If the resolution results in the advancement being granted, any increase in wages will be backdated to the relevant anniversary date.</p><p>e. An employee employed as a Children&#39;s Services Employee Level 2 on completion of an accredited introductory childcare course will immediately progress by one additional level beyond that determined in accordance with clause 14.2(a). Any additional steps will be subject to meeting the requirements of clause 14.2(a).</p></li><li><p>Junior employees</p><p>a. Junior employees employed as Children&#39;s Services Employees Level 3, 4 and 5 must be paid at the appropriate adult rate.</p></li></ol><p>[14.3(b) varied by <a href="https://www.fwc.gov.au/documents/awardsandorders/html/pr727866.htm" target="_blank" rel="noreferrer">PR727866</a> ppc 19Mar21]</p><p>b. Junior employees employed as Children&#39;s Services Employee Level 1 or Children&#39;s Services Employee Level 2 will be paid no less than the following percentages of the corresponding Children&#39;s Services Employee Level 2 rate:</p><p><strong>Age</strong> <strong>% of adult rate</strong></p><hr><p>Under 17 years 70 Under 18 years 80 Under 19 years 90</p><ol><li>Apprentices</li></ol><p>a. Apprentices will be engaged in accordance with the relevant apprenticeship legislation and paid no less than an unapprenticed junior of the same age.</p><p>b. For apprentices who commenced on or after 1 January 2014, the minimum rate of pay will be as set out in the table below, subject to the proviso in clause 14.4(a) that no apprentice will be paid less than an unapprenticed junior of the same age.</p><p><strong>Year of apprenticeship</strong> <strong>% of minimum rate for Children&#39;s Services Employee Level 3.1 for apprentices who have not completed year 12</strong> <strong>% of minimum rate for Children&#39;s Services Employee Level 3.1 for apprentices who have completed year 12</strong></p><hr><p>1st year 50 55 2nd and subsequent years 60 65</p><ol><li>Adult apprentices</li></ol><p>a. The minimum rate for an adult apprentice who commenced on or after 1 January 2014 and is in the first year of their apprenticeship will be 80% of the minimum rate for a Level 3.1, or the rate prescribed by clause 14.4, whichever is the greater.</p><p>b. The minimum rate for an adult apprentice who commenced on or after 1 January 2014 and is in the second and subsequent years of their apprenticeship must be the rate for the lowest adult classification in clause 14.1, or the rate prescribed by clause 14.4, whichever is the greater.</p><p>[14.5(c) varied by <a href="https://www.fwc.gov.au/documents/awardsandorders/html/PR733842.htm" target="_blank" rel="noreferrer">PR733842</a> from 27Sep21]</p><p>c. A person employed by an employer under this award immediately prior to entering into a training agreement as an adult apprentice with that employer must not suffer a reduction in their minimum wage by virtue of entering into the training agreement, provided that the person has been an employee in that enterprise for at least six months as a full-time employee or twelve months as a part-time or regular casual employee immediately prior to commencing the apprenticeship. For the purpose only of fixing a minimum wage, the adult apprentice must continue to receive the minimum wage that applies to the classification specified in clause 14.1 in which the adult apprentice was engaged immediately prior to entering into the training agreement.</p><ol><li>Apprentice conditions of employment</li></ol><p>a. Except as provided in this clause or where otherwise stated, all conditions of employment specified in this award apply to apprentices.</p><p>a. Where an apprentice is required to attend block release training for training identified in or associated with their training contract, and such training requires an overnight stay, the employer must pay for the excess reasonable travel costs incurred by the apprentice in the course of travelling to and from such training. Provided that this clause will not apply where the apprentice could attend an alternative Registered Training Organisation (RTO) and the use of the more distant RTO is not agreed between the employer and the apprentice.</p><p>b. For the purposes of clause 14.6(b) above, excess reasonable travel costs include the total costs of reasonable transportation (including transportation of tools where required), accommodation costs incurred while travelling (where necessary) and reasonable expenses incurred while travelling, including meals, which exceed those incurred in travelling to and from work. For the purposes of this subclause, excess travel costs do not include payment for travelling time or expenses incurred while not travelling to and from block release training.</p><p>c. The amount payable by an employer under clause 14.6(b) may be reduced by an amount the apprentice is eligible to receive for travel costs to attend block release training under a Government apprentice assistance scheme. This will only apply if an apprentice has either received such assistance or their employer has advised them in writing of the availability of such assistance.</p><p>d. All training fees charged by an RTO for prescribed courses and the cost of all prescribed textbooks (excluding those textbooks which are available in the employer&#39;s technical library) for the apprenticeship , which are paid by an apprentice, shall be reimbursed by the employer within six months of the commencement of the apprenticeship or the relevant stage of the apprenticeship, or within three months of the commencement of the training provided by the RTO, whichever is the later, unless there is unsatisfactory progress.</p><p>e. An employer may meet its obligations under clause 14.6(e) by paying any fees and/or cost of textbooks directly to the RTO.</p><p>f. An apprentice is entitled to be released from work without loss of continuity of employment and to payment of the appropriate wages to attend any training and assessment specified in, or associated with, the training contract.</p><p>g. Time spent by an apprentice in attending any training and/or assessment specified in, or associated with, the training contract is to be regarded as time worked for the employer for the purposes of calculating the apprentice&#39;s wages and determining the apprentice&#39;s employment conditions. This subclause operates subject to the provisions of <a href="/eba/ebas/childrens-services/schedules/e-school-based-apprentices.html">Schedule E</a>---School-based Apprentices.</p><p>h. No apprentice will, except in an emergency, work or be required to work overtime or shiftwork at times which would prevent their attendance at training consistent with their training contract.</p><ol><li>Supported wage system</li></ol><p>See <a href="/eba/ebas/childrens-services/schedules/c-supported-wage-system.html">Schedule C</a>.</p><ol><li>National training wage</li></ol><p>[14.8(a) varied by <a href="https://www.fwc.gov.au/documents/awardsandorders/html/pr720159.htm" target="_blank" rel="noreferrer">PR720159</a> ppc 18Jun20]</p><p>a. <a href="/eba/ebas/childrens-services/schedules/e-school-based-apprentices.html">Schedule E</a> to the <a href="https://www.fwc.gov.au/document-search/view/2/aHR0cHM6Ly9zYXNyY2RhdGFwcmRhdWVhYS5ibG9iLmNvcmUud2luZG93cy5uZXQvYXdhcmRzL01vZGVybkF3YXJkcy9NQTAwMDEwNC5kb2N40?sid=&amp;q=miscellaneous" target="_blank" rel="noreferrer"><em>Miscellaneous Award 2020</em></a> sets out minimum wage rates and conditions for employees undertaking traineeships.</p><p>[14.8(b) varied by <a href="https://www.fwc.gov.au/documents/awardsandorders/html/pr606446.htm" target="_blank" rel="noreferrer">PR606446</a><a href="https://www.fwc.gov.au/documents/awardsandorders/html/pr707547.htm" target="_blank" rel="noreferrer">, PR707547</a>, <a href="https://www.fwc.gov.au/documents/awardsandorders/html/pr720159.htm" target="_blank" rel="noreferrer">PR720159</a> ppc 18Jun20, <a href="https://www.fwc.gov.au/documents/awardsandorders/html/PR723827.htm" target="_blank" rel="noreferrer">PR723827</a>, <a href="https://www.fwc.gov.au/documents/awardsandorders/html/pr729383.htm" target="_blank" rel="noreferrer">PR729383</a>, <a href="https://www.fwc.gov.au/documents/awardsandorders/html/PR740806.htm" target="_blank" rel="noreferrer">PR740806</a>, <a href="https://www.fwc.gov.au/documents/awardsandorders/pdf/pr762229.pdf" target="_blank" rel="noreferrer">PR762229</a>, <a href="https://www.fwc.gov.au/documents/awardsandorders/pdf/pr774011.pdf" target="_blank" rel="noreferrer">PR774011</a>, <a href="https://www.fwc.gov.au/documents/awardsandorders/pdf/pr786659.pdf" target="_blank" rel="noreferrer">PR786659</a> ppc 01Jul25]</p><p>b. This award incorporates the terms of <a href="/eba/ebas/childrens-services/schedules/e-school-based-apprentices.html">Schedule E</a> to the <a href="https://www.fwc.gov.au/document-search/view/2/aHR0cHM6Ly9zYXNyY2RhdGFwcmRhdWVhYS5ibG9iLmNvcmUud2luZG93cy5uZXQvYXdhcmRzL01vZGVybkF3YXJkcy9NQTAwMDEwNC5kb2N40?sid=&amp;q=miscellaneous" target="_blank" rel="noreferrer"><em>Miscellaneous Award 2020</em></a> as at 1 July 2025. Provided that any reference to &quot;this award&quot; in <a href="/eba/ebas/childrens-services/schedules/e-school-based-apprentices.html">Schedule E</a> to the <a href="https://www.fwc.gov.au/document-search/view/2/aHR0cHM6Ly9zYXNyY2RhdGFwcmRhdWVhYS5ibG9iLmNvcmUud2luZG93cy5uZXQvYXdhcmRzL01vZGVybkF3YXJkcy9NQTAwMDEwNC5kb2N40?sid=&amp;q=miscellaneous" target="_blank" rel="noreferrer"><em>Miscellaneous Award 2020</em></a> is to be read as referring to the <em>Children&#39;s Services Award 2010</em> and not the <em><a href="https://www.fwc.gov.au/document-search/view/2/aHR0cHM6Ly9zYXNyY2RhdGFwcmRhdWVhYS5ibG9iLmNvcmUud2luZG93cy5uZXQvYXdhcmRzL01vZGVybkF3YXJkcy9NQTAwMDEwNC5kb2N40?sid=&amp;q=miscellaneous" target="_blank" rel="noreferrer">Miscellaneous Award 2020</a>.</em></p><p>[14.8(c) inserted by <a href="https://www.fwc.gov.au/documents/awardsandorders/html/pr718938.htm" target="_blank" rel="noreferrer">PR718938</a>; deleted by <a href="https://www.fwc.gov.au/documents/awardsandorders/html/PR723827.htm" target="_blank" rel="noreferrer">PR723827</a> ppc 01Nov20]</p><p>Plain language terms: pay rates, award rates, minimum rates.</p>`,46)])])}const u=r(i,[["render",s]]);export{m as __pageData,u as default};
